-- Backfill notificaciones.proyectoId from items.proyectoId
UPDATE notificaciones n 
JOIN items i ON n.itemId = i.id 
SET n.proyectoId = i.proyectoId 
WHERE n.proyectoId IS NULL AND n.itemId IS NOT NULL;

-- Set remaining notificaciones without itemId to Hidalma (1) since all existing data is Hidalma
UPDATE notificaciones SET proyectoId = 1 WHERE proyectoId IS NULL;

-- Backfill metas to Hidalma (1) since all existing metas are for Hidalma
UPDATE metas SET proyectoId = 1 WHERE proyectoId IS NULL;

-- Backfill bitacora to Hidalma (1) since all existing activity is for Hidalma
UPDATE bitacora SET proyectoId = 1 WHERE proyectoId IS NULL;

-- Add indexes for the new proyectoId columns
CREATE INDEX idx_notificaciones_proyecto ON notificaciones(proyectoId);
CREATE INDEX idx_bitacora_proyecto ON bitacora(proyectoId);
CREATE INDEX idx_metas_proyecto ON metas(proyectoId);

